@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings

<div class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings
@using sv_3d305c040f6d42d584265800cbee366a.Models

<div class="settings-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <div class="avatar-frame mb-2">
                    <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
                </div>
                <label class="form-label">Avatar URL</label>
                <input type="text" class="form-control form-control-sm" @bind="AvatarUrl" />
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert @(IsError ? "alert-danger" : "alert-success") mt-3 alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool IsSaving;
    private string? StatusMessage;
    private bool IsError;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Profile saved successfully!";
            IsError = false;
        }
        catch
        {
            StatusMessage = "Failed to save profile.";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            StatusMessage = null;
        }
    }
}

@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings
@using sv_3d305c040f6d42d584265800cbee366a.Models

<div class="settings-section">
    <h4>Notifications</h4>
    <p class="text-muted">Choose how you want to be notified</p>
    <hr />

    <div class="mb-4">
        <h6>General</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Channel Preferences</h6>
        <p class="text-muted small">Uncheck channels you want to mute</p>
        @foreach (var channel in AllChannels)
        {
            var ch = channel;
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                       checked="@(!MutedChannels.Contains(ch))"
                       @onchange="e => ToggleChannel(ch, (bool)(e.Value ?? false))" />
                <label class="form-check-label text-capitalize" for="@($"ch-{ch}")">@ch</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success mt-3 alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private HashSet<string> MutedChannels = [];
    private bool IsSaving;
    private string? StatusMessage;

    private static readonly string[] AllChannels = ["general", "engineering", "marketing", "design", "announcements"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private bool _initialized;

    private void ToggleChannel(string channel, bool enabled)
    {
        if (enabled)
            MutedChannels.Remove(channel);
        else
            MutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        StatusMessage = "Notification preferences saved!";
        IsSaving = false;
    }
}

@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="() => IsExpanded = !IsExpanded">
        <span>🔑 Change Password</span>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body mt-2">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }

            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success py-2">@SuccessMessage</div>
            }

            <button class="btn btn-warning" @onclick="SubmitAsync" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private string? SuccessMessage;
    private bool IsSubmitting;

    private async Task SubmitAsync()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully!";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch
        {
            ErrorMessage = "Failed to change password.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings
@using sv_3d305c040f6d42d584265800cbee366a.Models

<div class="settings-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security</p>
    <hr />

    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />
    </div>

    <div class="mb-4">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled" @onchange="ToggleTwoFactor" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </small>
        }
    </div>

    <div class="mb-4">
        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-sm table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (Sessions is not null)
                    {
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session != Sessions.First())
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>

    @if (SessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal fade show d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p class="mb-0"><strong>@SessionToRevoke.Device</strong> — @SessionToRevoke.Location</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                            @if (IsRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
