            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled" @onchange="ToggleTwoFactor" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </small>
        }
    </div>

    <div class="mb-4">
        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-sm table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (Sessions is not null)
                    {
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session != Sessions.First())
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>

    @if (SessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal fade show d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p class="mb-0"><strong>@SessionToRevoke.Device</strong> — @SessionToRevoke.Location</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                            @if (IsRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool TwoFactorEnabled;
    private List<ActiveSession>? Sessions;
    private ActiveSession? SessionToRevoke;
    private bool IsRevoking;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            Sessions = [.. Settings.Sessions];
            _initialized = true;
        }
        else if (Settings is not null)
        {
            Sessions = [.. Settings.Sessions];
        }
    }

    private async Task HandleChangePasswordAsync((string current, string newPwd) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task ToggleTwoFactor(ChangeEventArgs e)
    {
        TwoFactorEnabled = (bool)(e.Value ?? false);
        await OnToggleTwoFactor.InvokeAsync(TwoFactorEnabled);
    }

    private void PromptRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
        IsRevoking = false;
        SessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

