@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings
@using sv_3d305c040f6d42d584265800cbee366a.Models

<div class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize the look and feel</p>
    <hr />

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                               value="@theme" checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                               value="@size" checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="Language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Chinese">Chinese</option>
                </select>
            </div>

            <div class="mb-4">
                <h6>Compact Mode</h6>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">Enable compact layout</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (!string.IsNullOrEmpty(StatusMessage))
            {
                <div class="alert alert-success mt-3 alert-dismissible fade show" role="alert">
                    @StatusMessage
                    <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
                </div>
            }
        </div>

        <div class="col-md-6">
            <h6>Preview</h6>
            <div class="appearance-preview @PreviewThemeClass" style="font-size: @PreviewFontSize; padding: @PreviewPadding;">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p class="mb-1">This is how your content will look.</p>
                    <p class="mb-1 text-muted">Secondary text appears like this.</p>
                    <button class="btn btn-sm btn-primary mt-1">Action Button</button>
                </div>
                <div class="preview-footer text-muted">
                    <small>Language: @Language</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool IsSaving;
    private string? StatusMessage;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewPadding => CompactMode ? "0.5rem" : "1rem";

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        StatusMessage = "Appearance settings saved!";
        IsSaving = false;
    }
}

@page "/settings"
@rendermode InteractiveServer
@namespace sv_3d305c040f6d42d584265800cbee366a.Components.Pages.Settings
@using sv_3d305c040f6d42d584265800cbee366a.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@ActiveSection" OnSectionChanged="s => ActiveSection = s" />

    <div class="settings-content">
        @if (IsLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "Profile":
                    <ProfileSection Profile="@Profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@NotifPrefs" OnSave="SaveNotificationsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="@Security"
                                     OnChangePassword="HandleChangePasswordAsync"
                                     OnRevokeSession="HandleRevokeSessionAsync"
                                     OnToggleTwoFactor="HandleToggleTwoFactorAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@Appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string ActiveSection = "Profile";
    private bool IsLoading = true;

    private UserProfile? Profile;
    private NotificationPrefs? NotifPrefs;
    private SecuritySettings? Security;
    private AppearanceSettings? Appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        IsLoading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        Profile = profileTask.Result;
        NotifPrefs = notifTask.Result;
        Security = securityTask.Result;
        Appearance = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        Profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        NotifPrefs = prefs;
    }

    private async Task HandleChangePasswordAsync((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task HandleToggleTwoFactorAsync(bool enabled)
    {
        // In a real app, this would call the service
        return Task.CompletedTask;
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        Appearance = settings;
    }
}

