toolArgs.file_text:
.settings-dashboard {
    display: flex;
    gap: 0;
    min-height: 80vh;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
    margin-bottom: 0.5rem;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
    cursor: pointer;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content */
.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
}

/* Avatar */
.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0 auto;
    border: 3px solid #dee2e6;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.appearance-preview .preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.appearance-preview .preview-body {
    padding: 0.75rem 1rem;
}

.appearance-preview .preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-footer {
    border-color: #45475a;
}

.preview-dark .text-muted {
    color: #a6adc8 !important;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #f0f0f0;
}

/* Change password panel */
.change-password-panel .btn-outline-secondary {
    border-radius: 0.375rem;
}

/* Responsive */
@@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        min-width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
    }

    .settings-sidebar .nav {
        flex-direction: row;
        overflow-x: auto;
    }

    .settings-sidebar .nav-link {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
    }

    .settings-sidebar .nav-link.active {
        border-left-color: transparent;
        border-bottom-color: #0d6efd;
    }
}

